//! `baton-do remove` logic: unlink a data object permanently.
//!
//! Wraps the existing `RodsConnection::unlink_data_object` (which
//! itself wraps `shim_data_obj_unlink` over `rcDataObjUnlink`).
//! `FORCE_FLAG_KW` is set unconditionally inside the shim — the
//! object is removed permanently rather than moved to the user's
//! trash collection. Matches upstream baton's `remove`
//! (`baton/src/write.c:304-331`); there is no soft-delete via
//! this operation.
//!
//! Distinct from `baton-do rmdir` — `rmdir` is collection-only
//! and takes opt-in `recurse`/`force` flags. Type mismatch on
//! either errors before any iRODS call rather than auto-routing
//! (matches upstream's `represents_data_object` guard at
//! `baton/src/operations.c:752-755`).
//!
//! Collection targets are an error — `remove` is data-objects-
//! only.

use crate::connection::RodsConnection;
use crate::error::BatonError;
use crate::types::Target;

/// Remove the data object at `target.path()`. Echoes the input
/// target unchanged on success — pure side-effect operation.
///
/// No options struct: there are no caller-controlled flags. The
/// force / no-soft-delete behaviour is inherent to the
/// operation, matching upstream baton.
///
/// Collection inputs are an error before any iRODS call.
pub fn rm_one(
    conn: &mut RodsConnection,
    target: Target,
) -> Result<Target, BatonError> {
    let path = match &target {
        Target::DataObject(_) => target.path(),
        Target::Collection(c) => {
            return Err(BatonError {
                code: -1,
                message: format!(
                    "baton-do remove: target is a collection, not a data object: {}",
                    c.collection
                ),
            });
        }
    };
    conn.unlink_data_object(&path)?;
    Ok(target)
}

/// Same as [`rm_one`], but catches iRODS errors and emits the
/// input annotated with an `"error"` field instead of
/// propagating. Mirrors the rest of the operations layer's
/// `*_one_annotated` wrappers.
pub fn rm_one_annotated(
    conn: &mut RodsConnection,
    target: Target,
) -> Target {
    let fallback = target.clone();
    match rm_one(conn, target) {
        Ok(t) => t,
        Err(err) => {
            let mut annotated = fallback;
            annotated.set_error(err);
            annotated
        }
    }
}
